  import sailpoint.tools.Util;
  import java.io.File;
  import java.io.FileNotFoundException;
  import java.util.Scanner;
  import sailpoint.object.Custom;
  import sailpoint.object.Identity;
  import sailpoint.object.Workflow;
  import sailpoint.object.WorkflowLaunch;
  import sailpoint.api.Workflower;
  import java.text.SimpleDateFormat;
  import sailpoint.tools.Message;
  import sailpoint.object.TaskResult;
  import sailpoint.tools.GeneralException;


  import org.apache.commons.logging.LogFactory;
  import org.apache.commons.logging.Log;

  Log logger = LogFactory.getLog("Ascension-Rule-Bulk-Disable");


  /**
* @param filePath
* @return
*/
  public static List readInputFile(String filePath) {
    logger.debug("Entering method readInputFile ");

    String headerString = null;
    int headerLength = 0;
    List allUsersList = new ArrayList();
    String[] headerSplit = null;
    Map identityMap = null;
    Scanner sc = null;
    try {
      if (Util.isNotNullOrEmpty(filePath)) {
        File file = new File(filePath);
        if ((!file.exists()) || (file.isDirectory())) {
          logger.error("File doesnt exist");
          taskResult.addMessage(new Message(Message.Type.Warn, "Input file does not exist : "+filePath, null));

        } else {
          try {
            sc = new Scanner(file);
          } catch (FileNotFoundException fnex) {
            logger.error("FileNotFoundException : "+fnex.getMessage());
            taskResult.addMessage(new Message(Message.Type.Error, "File not found "+fnex.getMessage(), null));
          }
          while (sc.hasNextLine()) {
            String line = sc.nextLine();
            if (lineCount == 0) {
              headerString = line;
              lineCount++;
              continue;

            }
            if (Util.isNotNullOrEmpty(line)) {
              allUsersList.add(line);
              lineCount++;
            }
          }
        }
      }
      else{
        logger.error("Filepath is null");
        taskResult.addMessage(new Message(Message.Type.Error, "Filepath null", null));
      }
    }catch(Exception ex){
      logger.error("Exception readInputFile :: "+ex.getMessage());
      taskResult.addMessage(new Message(Message.Type.Error, "Exception : "+ex.getMessage(), null));
    } finally {
      if(sc != null)
        sc.close();
    }
    logger.debug("Exiting method readInputFile ");
    return allUsersList;
  }

  public Map processIdentities(String identityName){
    logger.debug("Entering method processIdentities");
    Map identityModel = new HashMap();

    if(Util.isNotNullOrEmpty(identityName)){

      Identity idn = context.getObjectByName(Identity.class, identityName);

      if(idn != null){

        identityModel.put("userName",identityName);

      }
    }
    logger.debug("Exiting method processIdentities");
    return identityModel;
  }

  public void launchImmediateTerminationWorkflow(Map identityModel){
    logger.debug("Entering method launchCreateWorkflow");
    Map args = new HashMap();
    WorkflowLaunch wflaunch = new WorkflowLaunch();
    Workflow wfInstance = context.getObjectByName(Workflow.class,"Ascension-Workflow-Immediate-Termination");
    if (wfInstance!=null){
      wflaunch.setWorkflowName(wfInstance.getName());
      wflaunch.setWorkflowRef(wfInstance.getName());
      wflaunch.setCaseName("Ascension or Amita Bulk Immediate termination proccess for "+identityModel.get("userName"));
    }
    args.put("identityModel",identityModel);
    args.put("workflowTrigger","rule");
    wflaunch.setVariables(args);
    Workflower workflower = new Workflower(context);
    WorkflowLaunch launch = workflower.launch(wflaunch);
    if(launch != null && launch.isFailed()){
      failedCount++;
      failedUserNames.add(identityModel.get("userName"));
    }
    else{
      successCount++;
      successUserNames.add(identityModel.get("userName"));
    }
    logger.debug("Exiting method launchCreateWorkflow");
  }

  /**
 * Rule logic starts
 *
 */
  List allUsersList = new ArrayList();
  String fileLocation ="";
  int lineCount = 0;
  int successCount = 0;
  int failedCount = 0;
  List successUserNames = new ArrayList();
  List failedUserNames = new ArrayList();
  if(taskResult == void || taskResult == null){
    taskResult = new TaskResult();
  }


  fileLocation = config.get("filePath");
  if(Util.isNotNullOrEmpty(fileLocation)){
    taskResult.setAttribute("fileLocation",fileLocation);

    allUsersList = readInputFile(fileLocation);
    //allUsersList.add("");
    //allUsersList.add("");

    logger.debug("===allUsersList : "+allUsersList);

    if(allUsersList != null && !allUsersList.isEmpty()){
      for(String identityName : allUsersList){
        Map identityModel = processIdentities(identityName);
        launchImmediateTerminationWorkflow(identityModel);
      }
    }
  }


  taskResult.setAttribute("recordCount",lineCount-1);
  taskResult.setAttribute("successCount",successCount);  
  taskResult.setAttribute("failedCount",failedCount);
  taskResult.setAttribute("successUserNames",successUserNames);
  taskResult.setAttribute("failedUserNames",failedUserNames);
  return ""+allUsersList;
